import React from 'react';
import Footer from '@components/Footer';
import Header from '@components/Header';
//import Seo from "./seo";

import * as styles from './fullWidthPage.module.css';

/** Full widdth layout component with header and footer
 * @param {Object} prop - Prop oject passed to this component
 * @param {Boolean} [prop.hideFooter=false] - Whether to not render the footer
 */
export default function FullWidthPageLayout({ children, hideFooter }) {
	return (
		<div id={styles.wrap}>
			{/* <Seo></Seo> */}
			<Header />
			<main>{children}</main>
			{!hideFooter && <Footer />}
		</div>
	);
}
